Variables.Expression:
=Max$(vCMEval)
	Aggr$(vCMEval)
    	$(vCMEvalBracket)Avg Sheet View Duration CM],
        AppID
    )
)

=Max$(vPMEval)
	Aggr$(vPMEval)
    	$(vPMEvalBracket)Avg Sheet View Duration PM],
        AppID
    )
)

=Max$(vPMEval)
	Aggr$(vPMEval)
    	$(vPMEvalBracket)Avg Sheet View Duration PMTD],
        AppID
    )
)

Measures.Expression:
RangeMax(
    Max(
        Aggr(
            {<SessionInCurrentMTD={1}>}Count(DISTINCT SheetConsumptionEventID)/Count(DISTINCT SessionID),
            SessionDay
        )
    ),
    Max(
        Aggr(
            {<SessionInPriorMTD={1}>}Count(DISTINCT SheetConsumptionEventID)/Count(DISTINCT SessionID),
            SessionDay
        )
    )
)
